ex("Aggregate Functions","Use SQL aggregate functions: COUNT, SUM, AVG, MIN, MAX.","databases","aggregates",2,"import sqlite3\n\n# TODO: Create sales table and use aggregate functions\n","Count: 5\nTotal: 850\nAverage: 170.00\nMin: 50\nMax: 300","Use GROUP BY with aggregate functions for categories.","import sqlite3\n\nconn = sqlite3.connect(':memory:')\nc = conn.cursor()\nc.execute('CREATE TABLE sales (product TEXT, amount INTEGER)')\nc.executemany('INSERT INTO sales VALUES (?,?)', [('A',200),('B',150),('A',300),('B',50),('A',150)])\nconn.commit()\n\nc.execute('SELECT COUNT(*), SUM(amount), AVG(amount), MIN(amount), MAX(amount) FROM sales')\ncount, total, avg, mn, mx = c.fetchone()\nprint(f'Count: {count}')\nprint(f'Total: {total}')\nprint(f'Average: {avg:.2f}')\nprint(f'Min: {mn}')\nprint(f'Max: {mx}')\nconn.close()","Aggregate functions operate on sets of rows. They're often combined with GROUP BY to get per-category statistics. HAVING filters groups (unlike WHERE which filters rows).","EC: H4.2")
ex("Database Normalisation","Demonstrate 1NF, 2NF, 3NF normalisation concepts with code.","databases","normalisation",4,"import sqlite3\n\n# TODO: Show unnormalised vs normalised schema\n","Unnormalised has redundancy\nNormalised: 3 tables, no redundancy","Split data into related tables connected by foreign keys.","import sqlite3\n\nconn = sqlite3.connect(':memory:')\nc = conn.cursor()\n\n# Normalised schema (3NF)\nc.execute('CREATE TABLE departments (id INTEGER PRIMARY KEY, name TEXT)')\nc.execute('CREATE TABLE teachers (id INTEGER PRIMARY KEY, name TEXT, dept_id INTEGER REFERENCES departments(id))')\nc.execute('CREATE TABLE courses (id INTEGER PRIMARY KEY, name TEXT, teacher_id INTEGER REFERENCES teachers(id))')\n\nc.executemany('INSERT INTO departments VALUES (?,?)', [(1,'Science'),(2,'Maths')])\nc.executemany('INSERT INTO teachers VALUES (?,?,?)', [(1,'Alice',1),(2,'Bob',2)])\nc.executemany('INSERT INTO courses VALUES (?,?,?)', [(1,'Physics',1),(2,'Chemistry',1),(3,'Algebra',2)])\nconn.commit()\n\nprint('Unnormalised has redundancy')\nprint(f'Normalised: 3 tables, no redundancy')\nconn.close()","Normalisation reduces redundancy: 1NF eliminates repeating groups, 2NF removes partial dependencies, 3NF removes transitive dependencies. Each table should represent one entity.","EC: H4.1")
ex("Transaction Management","Use transactions to ensure data consistency with commit and rollback.","databases","transactions",4,"import sqlite3\n\n# TODO: Demonstrate transaction with rollback on error\n","Balance after transfer: 900 and 600\nAfter failed transfer: 900 and 600 (unchanged)","Use conn.execute() in a try/except with rollback.","import sqlite3\n\nconn = sqlite3.connect(':memory:')\nc = conn.cursor()\nc.execute('CREATE TABLE accounts (name TEXT, balance INTEGER)')\nc.executemany('INSERT INTO accounts VALUES (?,?)', [('Alice',1000),('Bob',500)])\nconn.commit()\n\n# Successful transfer\ntry:\n    c.execute('UPDATE accounts SET balance = balance - 100 WHERE name = ?', ('Alice',))\n    c.execute('UPDATE accounts SET balance = balance + 100 WHERE name = ?', ('Bob',))\n    conn.commit()\nexcept:\n    conn.rollback()\n\nbalances = dict(c.execute('SELECT name, balance FROM accounts').fetchall())\nprint(f'Balance after transfer: {balances[\"Alice\"]} and {balances[\"Bob\"]}')\n\n# Failed transfer\ntry:\n    c.execute('UPDATE accounts SET balance = balance - 5000 WHERE name = ?', ('Alice',))\n    raise ValueError('Insufficient funds')\n    conn.commit()\nexcept:\n    conn.rollback()\n\nbalances = dict(c.execute('SELECT name, balance FROM accounts').fetchall())\nprint(f'After failed transfer: {balances[\"Alice\"]} and {balances[\"Bob\"]} (unchanged)')\nconn.close()","Transactions ensure atomicity — either all operations succeed (commit) or none do (rollback). This prevents partial updates that would leave data in an inconsistent state.","EC: H4.2")

# === WEB & API (10 more) ===
ex("JSON API Response Handling","Parse and process a JSON API response structure.","web_and_api","json","2","import json\n\napi_response = '{\"status\":\"ok\",\"data\":{\"users\":[{\"name\":\"Alice\",\"age\":25},{\"name\":\"Bob\",\"age\":30}]},\"count\":2}'\n# TODO: Parse and extract user names\n","Status: ok\nUsers: Alice, Bob\nCount: 2","Use json.loads() to parse, then navigate the dict.","import json\n\napi_response = '{\"status\":\"ok\",\"data\":{\"users\":[{\"name\":\"Alice\",\"age\":25},{\"name\":\"Bob\",\"age\":30}]},\"count\":2}'\ndata = json.loads(api_response)\nprint(f'Status: {data[\"status\"]}')\nnames = [u['name'] for u in data['data']['users']]\nprint(f'Users: {\", \".join(names)}')\nprint(f'Count: {data[\"count\"]}')","API responses are typically nested JSON. Navigate with dictionary key access and use list comprehensions to extract fields from arrays of objects.","SE: P6")
ex("URL Parsing","Parse and construct URLs using urllib.parse.","web_and_api","urls",2,"from urllib.parse import urlparse, urlencode, urlunparse\n\n# TODO: Parse a URL and construct a new one with query params\n","Scheme: https\nHost: api.example.com\nPath: /v2/users\nBuilt: https://api.example.com/search?q=python&page=1","Use urlparse() to decompose and urlencode() to build query strings.","from urllib.parse import urlparse, urlencode, urlunparse\n\nurl = 'https://api.example.com/v2/users?limit=10'\nparsed = urlparse(url)\nprint(f'Scheme: {parsed.scheme}')\nprint(f'Host: {parsed.netloc}')\nprint(f'Path: {parsed.path}')\n\nparams = urlencode({'q': 'python', 'page': 1})\nnew_url = f'https://api.example.com/search?{params}'\nprint(f'Built: {new_url}')","urllib.parse provides safe URL manipulation. urlencode handles special characters and spaces properly. Never concatenate URL parameters manually — use urlencode for safety.","SE: P6")
ex("HTTP Status Code Handler","Create a response handler that processes different HTTP status codes.","web_and_api","http",3,"def handle_response(status_code, body=''):\n    # TODO: Handle different status code ranges\n    pass\n\nfor code in [200, 201, 301, 400, 404, 500]:\n    print(f'{code}: {handle_response(code)}')","200: OK - Success\n201: Created - Resource created\n301: Redirect - Resource moved\n400: Bad Request - Client error\n404: Not Found - Resource not found\n500: Internal Server Error - Server error","Group by ranges: 2xx success, 3xx redirect, 4xx client error, 5xx server error.","def handle_response(status_code, body=''):\n    status_map = {\n        200: 'OK - Success',\n        201: 'Created - Resource created',\n        301: 'Redirect - Resource moved',\n        400: 'Bad Request - Client error',\n        404: 'Not Found - Resource not found',\n        500: 'Internal Server Error - Server error'\n    }\n    return status_map.get(status_code, f'Unknown status {status_code}')\n\nfor code in [200, 201, 301, 400, 404, 500]:\n    print(f'{code}: {handle_response(code)}')","HTTP status codes follow a pattern: 2xx success, 3xx redirect, 4xx client error, 5xx server error. Understanding these is essential for API development and debugging.","SE: P6")

# === DATA SCIENCE (10 more) ===
ex("Frequency Distribution","Calculate and display a frequency distribution table.","data_science","statistics",2,"data = [3, 7, 7, 2, 5, 3, 7, 8, 3, 5, 2, 7, 3]\n# TODO: Create frequency table sorted by value\n","Value | Freq | Pct\n  2   |   2  | 15.4%\n  3   |   4  | 30.8%\n  5   |   2  | 15.4%\n  7   |   4  | 30.8%\n  8   |   1  |  7.7%","Count occurrences, calculate percentages.","data = [3, 7, 7, 2, 5, 3, 7, 8, 3, 5, 2, 7, 3]\nfrom collections import Counter\ncounts = Counter(data)\ntotal = len(data)\n\nprint('Value | Freq | Pct')\nfor val in sorted(counts):\n    freq = counts[val]\n    pct = freq / total * 100\n    print(f'  {val}   |   {freq}  | {pct:.1f}%')","Frequency distributions show how often each value appears. They're the foundation of histograms and essential for understanding data patterns before deeper analysis.","SE: P6")
ex("Moving Average","Calculate a simple moving average for time series smoothing.","data_science","time_series",3,"def moving_average(data, window):\n    # TODO: Calculate moving average\n    pass\n\nprices = [100, 102, 101, 105, 107, 106, 110, 108]\nprint(moving_average(prices, 3))","[101.0, 102.67, 104.33, 106.0, 107.67, 108.0]","Average each window of consecutive values.","def moving_average(data, window):\n    result = []\n    for i in range(len(data) - window + 1):\n        avg = sum(data[i:i+window]) / window\n        result.append(round(avg, 2))\n    return result\n\nprices = [100, 102, 101, 105, 107, 106, 110, 108]\nprint(moving_average(prices, 3))","Moving averages smooth noisy data by averaging over a sliding window. Larger windows produce smoother curves but introduce more lag. This is used extensively in finance and signal processing.","SE: P6")
ex("Correlation Coefficient","Calculate Pearson correlation coefficient between two variables.","data_science","statistics",4,"def pearson_r(x, y):\n    # TODO: Calculate correlation\n    pass\n\nhours_studied = [1, 2, 3, 4, 5, 6, 7, 8]\ntest_scores = [52, 58, 65, 71, 75, 82, 88, 91]\nprint(f'Correlation: {pearson_r(hours_studied, test_scores):.4f}')","Correlation: 0.9968","r = Σ((xi-x̄)(yi-ȳ)) / sqrt(Σ(xi-x̄)² * Σ(yi-ȳ)²)","def pearson_r(x, y):\n    n = len(x)\n    mean_x = sum(x) / n\n    mean_y = sum(y) / n\n    numerator = sum((xi - mean_x) * (yi - mean_y) for xi, yi in zip(x, y))\n    denom_x = sum((xi - mean_x)**2 for xi in x) ** 0.5\n    denom_y = sum((yi - mean_y)**2 for yi in y) ** 0.5\n    return numerator / (denom_x * denom_y)\n\nhours_studied = [1, 2, 3, 4, 5, 6, 7, 8]\ntest_scores = [52, 58, 65, 71, 75, 82, 88, 91]\nprint(f'Correlation: {pearson_r(hours_studied, test_scores):.4f}')","Pearson's r measures linear correlation: +1 is perfect positive, -1 perfect negative, 0 is no linear relationship. Values above 0.8 indicate strong correlation.","SE: P3")

# === AUTOMATION & TESTING (15 more) ===
ex("Pytest Style Tests","Write tests using pytest conventions (no class needed).","automation_and_testing","pytest",2,"# TODO: Write pytest-style test functions\ndef add(a, b): return a + b\ndef divide(a, b):\n    if b == 0: raise ValueError\n    return a / b\n\n# Run tests manually\n","test_add_positive: PASSED\ntest_add_negative: PASSED\ntest_divide_by_zero: PASSED","Pytest uses plain functions with assert statements.","def add(a, b): return a + b\ndef divide(a, b):\n    if b == 0: raise ValueError\n    return a / b\n\ndef test_add_positive():\n    assert add(2, 3) == 5\n\ndef test_add_negative():\n    assert add(-1, -1) == -2\n\ndef test_divide_by_zero():\n    try:\n        divide(1, 0)\n        assert False, 'Should have raised'\n    except ValueError:\n        pass\n\nfor test in [test_add_positive, test_add_negative, test_divide_by_zero]:\n    try:\n        test()\n        print(f'{test.__name__}: PASSED')\n    except AssertionError as e:\n        print(f'{test.__name__}: FAILED - {e}')","Pytest uses plain assert statements instead of unittest's self.assertEqual. Function names starting with test_ are auto-discovered. This is simpler and more Pythonic than unittest.","SE: P4")
ex("Mock Objects","Use unittest.mock to test code with external dependencies.","automation_and_testing","mocking",4,"from unittest.mock import Mock, patch\n\n# TODO: Mock an API call and test the function that uses it\n","User: Alice (mocked)\nAPI was called with: /users/1","Create a Mock object that returns predetermined values.","from unittest.mock import Mock, patch\n\ndef get_user(api_client, user_id):\n    response = api_client.get(f'/users/{user_id}')\n    return response['name']\n\nmock_api = Mock()\nmock_api.get.return_value = {'name': 'Alice', 'id': 1}\n\nresult = get_user(mock_api, 1)\nprint(f'User: {result} (mocked)')\nprint(f'API was called with: {mock_api.get.call_args[0][0]}')","Mocking replaces real dependencies with controlled fakes during testing. This isolates the unit under test and makes tests fast, deterministic, and independent of external services.","SE: P4")
ex("Regex Pattern Matching","Use regex to extract structured data from text.","automation_and_testing","regex",3,"import re\n\ntext = 'Contact: alice@email.com or bob@school.edu. Call 0412-345-678 or 02-9876-5432.'\n# TODO: Extract emails and phone numbers\n","Emails: ['alice@email.com', 'bob@school.edu']\nPhones: ['0412-345-678', '02-9876-5432']","Use re.findall() with appropriate patterns.","import re\n\ntext = 'Contact: alice@email.com or bob@school.edu. Call 0412-345-678 or 02-9876-5432.'\n\nemails = re.findall(r'[\\w.+-]+@[\\w-]+\\.[\\w.]+', text)\nphones = re.findall(r'\\d{2,4}-\\d{3,4}-\\d{3,4}', text)\n\nprint(f'Emails: {emails}')\nprint(f'Phones: {phones}')","re.findall() returns all non-overlapping matches. \\w matches word characters, \\d matches digits. Quantifiers {2,4} specify min-max repetitions.","SE: P4")
ex("Logging Module","Set up proper logging with different levels and formatters.","automation_and_testing","logging",3,"import logging\n\n# TODO: Configure logging and show different levels\n","DEBUG: Detailed information\nINFO: General information\nWARNING: Something unexpected\nERROR: Something failed","Use logging.basicConfig() with format and level.","import logging\nimport sys\n\nlogging.basicConfig(\n    level=logging.DEBUG,\n    format='%(levelname)s: %(message)s',\n    stream=sys.stdout\n)\n\nlogger = logging.getLogger(__name__)\nlogger.debug('Detailed information')\nlogger.info('General information')\nlogger.warning('Something unexpected')\nlogger.error('Something failed')","The logging module provides 5 levels: DEBUG, INFO, WARNING, ERROR, CRITICAL. Production code should use logging instead of print() for proper log management, filtering, and rotation.","SE: P4")
ex("Batch File Renamer","Create a script to batch rename files with a pattern.","automation_and_testing","automation",3,"import os\n\n# TODO: Create sample files and rename them with a pattern\n","Renamed: file_001.txt, file_002.txt, file_003.txt","Use os.listdir() and os.rename() with f-string formatting.","import os\n\n# Create sample files\nos.makedirs('test_rename', exist_ok=True)\nfor i in range(3):\n    open(f'test_rename/doc{i}.txt', 'w').close()\n\n# Rename with pattern\nfiles = sorted(os.listdir('test_rename'))\nrenamed = []\nfor i, f in enumerate(files, 1):\n    old = os.path.join('test_rename', f)\n    new_name = f'file_{i:03d}.txt'\n    new = os.path.join('test_rename', new_name)\n    os.rename(old, new)\n    renamed.append(new_name)\n\nprint(f'Renamed: {\", \".join(renamed)}')\n\n# Cleanup\nfor f in os.listdir('test_rename'):\n    os.remove(os.path.join('test_rename', f))\nos.rmdir('test_rename')","Batch renaming is a common automation task. Using enumerate with a start value and format specifiers creates sequential, zero-padded filenames.","SE: P6")

# === SECURITY (10 more) ===
ex("Rate Limiter","Implement a simple rate limiter using a sliding window.","security","rate_limiting",4,"import time\n\nclass RateLimiter:\n    # TODO: Allow max_requests per window_seconds\n    pass\n\nlimiter = RateLimiter(max_requests=3, window_seconds=1)\nfor i in range(5):\n    result = limiter.allow()\n    print(f'Request {i+1}: {\"Allowed\" if result else \"Denied\"}')","Request 1: Allowed\nRequest 2: Allowed\nRequest 3: Allowed\nRequest 4: Denied\nRequest 5: Denied","Track request timestamps and remove expired ones.","import time\nfrom collections import deque\n\nclass RateLimiter:\n    def __init__(self, max_requests, window_seconds):\n        self.max_requests = max_requests\n        self.window = window_seconds\n        self.requests = deque()\n    def allow(self):\n        now = time.time()\n        while self.requests and self.requests[0] < now - self.window:\n            self.requests.popleft()\n        if len(self.requests) < self.max_requests:\n            self.requests.append(now)\n            return True\n        return False\n\nlimiter = RateLimiter(max_requests=3, window_seconds=1)\nfor i in range(5):\n    result = limiter.allow()\n    print(f'Request {i+1}: {\"Allowed\" if result else \"Denied\"}')","Sliding window rate limiters track recent request timestamps. Old timestamps are pruned. This protects APIs from abuse and DoS attacks. deque's popleft() is O(1).","EC: H6.2")
ex("Environment Variables for Secrets","Use environment variables instead of hardcoding secrets.","security","secrets_management",2,"import os\n\n# TODO: Show safe vs unsafe secret handling\n","UNSAFE: Never hardcode secrets!\nSAFE: Use os.environ.get() with defaults","Never commit secrets to code. Use .env files or env vars.","import os\n\n# UNSAFE (never do this)\n# api_key = 'sk-1234567890abcdef'\nprint('UNSAFE: Never hardcode secrets!')\n\n# SAFE\napi_key = os.environ.get('API_KEY', 'not-set')\ndb_url = os.environ.get('DATABASE_URL', 'sqlite:///default.db')\nprint('SAFE: Use os.environ.get() with defaults')","Environment variables keep secrets out of source code. Use .env files locally (with python-dotenv) and platform-specific secret managers in production.","EC: H6.2")
ex("CSRF Token Generation","Generate and validate CSRF tokens for form submissions.","security","web_security",4,"import secrets\nimport hmac\nimport hashlib\n\n# TODO: Generate and validate CSRF tokens\n","Token generated: (hex string)\nValid token: True\nTampered token: False","Use HMAC with a secret key for token generation.","import secrets\nimport hmac\nimport hashlib\n\nSECRET_KEY = secrets.token_bytes(32)\n\ndef generate_csrf_token(session_id):\n    return hmac.new(SECRET_KEY, session_id.encode(), hashlib.sha256).hexdigest()\n\ndef validate_csrf_token(session_id, token):\n    expected = generate_csrf_token(session_id)\n    return hmac.compare_digest(expected, token)\n\nsession = 'user-session-123'\ntoken = generate_csrf_token(session)\nprint(f'Token generated: {token[:20]}...')\nprint(f'Valid token: {validate_csrf_token(session, token)}')\nprint(f'Tampered token: {validate_csrf_token(session, \"fake-token\")}')","CSRF tokens prevent cross-site request forgery by binding form submissions to user sessions. hmac.compare_digest() is timing-safe, preventing timing attacks.","EC: H6.2")
ex("Audit Logger","Create an audit logging system that records all security-relevant events.","security","audit_logging",3,"from datetime import datetime\n\nclass AuditLogger:\n    # TODO: Log events with timestamp, user, action, and result\n    pass\n\naudit = AuditLogger()\naudit.log('alice', 'login', 'success')\naudit.log('bob', 'login', 'failed')\naudit.log('alice', 'delete_file', 'success')\naudit.show_logs()","[2026-03-17 ...] alice | login | success\n[2026-03-17 ...] bob | login | failed\n[2026-03-17 ...] alice | delete_file | success","Store events as dicts with timestamps.","from datetime import datetime\n\nclass AuditLogger:\n    def __init__(self):\n        self.logs = []\n    def log(self, user, action, result):\n        self.logs.append({\n            'timestamp': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),\n            'user': user,\n            'action': action,\n            'result': result\n        })\n    def show_logs(self):\n        for entry in self.logs:\n            print(f'[{entry[\"timestamp\"]}] {entry[\"user\"]} | {entry[\"action\"]} | {entry[\"result\"]}')\n\naudit = AuditLogger()\naudit.log('alice', 'login', 'success')\naudit.log('bob', 'login', 'failed')\naudit.log('alice', 'delete_file', 'success')\naudit.show_logs()","Audit logs create a tamper-evident record of security events. They're essential for compliance (GDPR, SOC2) and incident response. In production, write to append-only storage.","EC: H6.2")
ex("Role-Based Access Control","Implement RBAC for authorising user actions.","security","authorisation",4,"class RBAC:\n    # TODO: Implement role-based permissions\n    pass\n\nrbac = RBAC()\nrbac.add_role('admin', ['read', 'write', 'delete'])\nrbac.add_role('editor', ['read', 'write'])\nrbac.add_role('viewer', ['read'])\nrbac.assign_role('alice', 'admin')\nrbac.assign_role('bob', 'editor')\n\nprint(rbac.can('alice', 'delete'))\nprint(rbac.can('bob', 'delete'))\nprint(rbac.can('bob', 'write'))","True\nFalse\nTrue","Map roles to permission sets, users to roles.","class RBAC:\n    def __init__(self):\n        self.roles = {}\n        self.user_roles = {}\n    def add_role(self, role, permissions):\n        self.roles[role] = set(permissions)\n    def assign_role(self, user, role):\n        self.user_roles[user] = role\n    def can(self, user, permission):\n        role = self.user_roles.get(user)\n        if not role:\n            return False\n        return permission in self.roles.get(role, set())\n\nrbac = RBAC()\nrbac.add_role('admin', ['read', 'write', 'delete'])\nrbac.add_role('editor', ['read', 'write'])\nrbac.add_role('viewer', ['read'])\nrbac.assign_role('alice', 'admin')\nrbac.assign_role('bob', 'editor')\n\nprint(rbac.can('alice', 'delete'))\nprint(rbac.can('bob', 'delete'))\nprint(rbac.can('bob', 'write'))","RBAC separates who users are (roles) from what they can do (permissions). This simplifies access management — change a role's permissions once, and all users with that role are updated.","EC: H6.2")

